import os
import hashlib
import secrets
import time
import re
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

# In-memory stores (use a proper database in production)
users_db = {}
tokens_db = {}

TOKEN_EXPIRY_SECONDS = 3600  # 1 hour


def hash_password(password, salt=None):
    """Hash password with salt using SHA-256."""
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        salt.encode('utf-8'),
        iterations=100000
    )
    return salt, hashed.hex()


def validate_username(username):
    """Validate username format."""
    if not isinstance(username, str):
        return False
    if len(username) < 3 or len(username) > 50:
        return False
    if not re.match(r'^[a-zA-Z0-9_]+$', username):
        return False
    return True


def validate_password(password):
    """Validate password strength."""
    if not isinstance(password, str):
        return False
    if len(password) < 8 or len(password) > 128:
        return False
    return True


def generate_token():
    """Generate a cryptographically secure token."""
    return secrets.token_urlsafe(48)


def cleanup_expired_tokens():
    """Remove expired tokens from the store."""
    current_time = time.time()
    expired = [
        token for token, data in tokens_db.items()
        if current_time - data['created_at'] > TOKEN_EXPIRY_SECONDS
    ]
    for token in expired:
        del tokens_db[token]


def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None

        auth_header = request.headers.get('Authorization')
        if auth_header:
            parts = auth_header.split()
            if len(parts) == 2 and parts[0].lower() == 'bearer':
                token = parts[1]

        if not token:
            return jsonify({'error': 'Authentication token is missing'}), 401

        cleanup_expired_tokens()

        token_data = tokens_db.get(token)
        if not token_data:
            return jsonify({'error': 'Invalid or expired token'}), 401

        if time.time() - token_data['created_at'] > TOKEN_EXPIRY_SECONDS:
            tokens_db.pop(token, None)
            return jsonify({'error': 'Token has expired'}), 401

        current_user = token_data['username']
        return f(current_user, *args, **kwargs)

    return decorated


@app.route('/api/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    if not validate_username(username):
        return jsonify({
            'error': 'Username must be 3-50 characters long and contain only alphanumeric characters and underscores'
        }), 400

    if not validate_password(password):
        return jsonify({
            'error': 'Password must be between 8 and 128 characters long'
        }), 400

    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 409

    salt, hashed_password = hash_password(password)
    users_db[username] = {
        'salt': salt,
        'password_hash': hashed_password
    }

    return jsonify({'message': 'User registered successfully'}), 201


@app.route('/api/login', methods=['POST'])
def login():
    """Authenticate user and return a token."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    # Use constant-time comparison to prevent timing attacks
    user = users_db.get(username)
    if not user:
        # Still hash to prevent timing attacks revealing user existence
        hash_password("dummy_password")
        return jsonify({'error': 'Invalid username or password'}), 401

    salt = user['salt']
    _, hashed_password = hash_password(password, salt)

    if not secrets.compare_digest(hashed_password, user['password_hash']):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Invalidate any existing tokens for this user
    existing_tokens = [
        t for t, d in tokens_db.items() if d['username'] == username
    ]
    for t in existing_tokens:
        del tokens_db[t]

    # Generate new token
    token = generate_token()
    tokens_db[token] = {
        'username': username,
        'created_at': time.time()
    }

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_in': TOKEN_EXPIRY_SECONDS
    }), 200


@app.route('/api/logout', methods=['POST'])
@token_required
def logout(current_user):
    """Invalidate the current token."""
    auth_header = request.headers.get('Authorization')
    if auth_header:
        parts = auth_header.split()
        if len(parts) == 2:
            token = parts[1]
            tokens_db.pop(token, None)

    return jsonify({'message': 'Logged out successfully'}), 200


