@app.route('/api/change-password', methods=['POST'])
@token_required
def change_password(current_user):
    """Change the current user's password."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    old_password = data.get('old_password')
    new_password = data.get('new_password')

    if not old_password or not new_password:
        return jsonify({'error': 'Old password and new password are required'}), 400

    if not validate_password(new_password):
        return jsonify({
            'error': 'New password must be between 8 and 128 characters long'
        }), 400

    user = users_db.get(current_user)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    # Verify old password
    salt = user['salt']
    _, hashed_old = hash_password(old_password, salt)

    if not secrets.compare_digest(hashed_old, user['password_hash']):
        return jsonify({'error': 'Old password is incorrect'}), 401

    # Set new password
    new_salt, new_hash = hash_password(new_password)
    users_db[current_user] = {
        'salt': new_salt,
        'password_hash': new_hash
    }

    # Invalidate all tokens for this user
    user_tokens = [
        t for t, d in tokens_db.items() if d['username'] == current_user
    ]
    for t in user_tokens:
        del tokens_db[t]

    return jsonify({'message': 'Password changed successfully. Please login again.'}), 200


